/// Extract the primary type string from a schema, handling both `"type": "string"`
/// and `"type": ["string", "null"]` forms. Returns the first non-null type from
/// an array, or the single type string.
fn extract_primary_type(schema: &serde_json::Value) -> Option<String> {
    match schema.get("type") {
        Some(serde_json::Value::String(s)) => Some(s.clone()),
        Some(serde_json::Value::Array(arr)) => {
            arr.iter()
                .filter_map(|v| v.as_str())
                .find(|s| *s != "null")
                .map(|s| s.to_string())
        }
        _ => None,
    }
}

