/// Extract the primary type string from a schema, handling both `"type": "string"`
/// and `"type": ["string", "null"]` forms. Also handles the common nullable
/// pattern `{"anyOf": [{"type": "string"}, {"type": "null"}]}`.
/// Returns the first non-null type.
fn extract_primary_type(schema: &serde_json::Value) -> Option<String> {
    match schema.get("type") {
        Some(serde_json::Value::String(s)) => return Some(s.clone()),
        Some(serde_json::Value::Array(arr)) => {
            if let Some(t) = arr.iter().filter_map(|v| v.as_str()).find(|s| *s != "null") {
                return Some(t.to_string());
            }
        }
        _ => {}
    }

    // Handle anyOf/oneOf nullable pattern: look for first branch with a type.
    for key in ["anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                if let Some(serde_json::Value::String(t)) = branch.get("type") {
                    if t != "null" {
                        return Some(t.clone());
                    }
                }
            }
        }
    }

    None
}

