fn deduplicate_suggestions(suggestions: &mut Vec<ValueSuggestion>) {
    let mut seen = HashSet::new();
    suggestions.retain(|s| {
        let key = match s {
            ValueSuggestion::Enum(v) | ValueSuggestion::Const(v) => {
                serde_json::to_string(v).unwrap_or_default()
            }
            ValueSuggestion::Boolean => "__boolean__".to_string(),
            ValueSuggestion::Null => "__null__".to_string(),
        };
        seen.insert(key)
    });
}

