/// Completion includes documentation from schema description.
#[tokio::test]
async fn completion_includes_documentation() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_schema("");
    let uri = doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let items = result["items"].as_array().unwrap();
    let name_item = items.iter().find(|i| i["label"] == "name").unwrap();

    let doc = name_item["documentation"]["value"].as_str().unwrap();
    assert!(
        doc.contains("The user's full name"),
        "expected description in documentation, got: {doc}"
    );
}

input.newString:
    let doc = name_item["documentation"]["value"].as_str().unwrap();
    assert!(
        doc.contains("The user's full name"),
        "expected description in documentation, got: {doc}"
    );
}

/// Helper: build a document with a custom schema file.
fn doc_with_custom_schema(schema_filename: &str, content: &str) -> (String, String) {
    let schema_path = format!(
        "{}/tests/fixtures/{schema_filename}",
        env!("CARGO_MANIFEST_DIR")
    );
    let doc = if content.is_empty() {
        format!(r#"{{"$schema": "{schema_path}"}}"#)
    } else {
        format!(r#"{{"$schema": "{schema_path}", {content}}}"#)
    };
    let uri = file_uri(&format!(
        "{}/tests/fixtures/test-completion-doc.json",
        env!("CARGO_MANIFEST_DIR")
    ));
    (doc, uri)
}

/// anyOf composition merges properties from all branches.
#[tokio::test]
async fn completion_anyof_merges_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let (content, uri) = doc_with_custom_schema("completion-anyOf-schema.json", "");
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    assert!(
        names.contains(&"name".to_string()),
        "expected 'name' from anyOf branch 1, got: {names:?}"
    );
    assert!(
        names.contains(&"age".to_string()),
        "expected 'age' from anyOf branch 2, got: {names:?}"
    );
}

/// anyOf required properties are marked correctly.
#[tokio::test]
async fn completion_anyof_preserves_required() {
    let mut client = TestClient::new();
    client.initialize().await;

    let (content, uri) = doc_with_custom_schema("completion-anyOf-schema.json", "");
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let items = result["items"].as_array().unwrap();
    let name_item = items.iter().find(|i| i["label"] == "name").unwrap();
    let detail = name_item["detail"].as_str().unwrap();
    assert!(
        detail.contains("required"),
        "expected 'name' to be required, detail: {detail}"
    );
}

/// oneOf nested object completions resolve into each branch.
#[tokio::test]
async fn completion_oneof_nested_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let (content, uri) = doc_with_custom_schema("completion-oneOf-schema.json", r#""contact": {}"#);
    open_and_wait(&mut client, &uri, &content).await;

    // Cursor inside contact {}
    let inner_brace = content.rfind('{').unwrap();
    let cursor_col = (inner_brace + 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    assert!(
        names.contains(&"email".to_string()),
        "expected 'email' from oneOf branch 1, got: {names:?}"
    );
    assert!(
        names.contains(&"phone".to_string()),
        "expected 'phone' from oneOf branch 2, got: {names:?}"
    );
}

/// Nullable type array suggests null value.
#[tokio::test]
async fn completion_nullable_type_array_suggests_null() {
    let mut client = TestClient::new();
    client.initialize().await;

    let (content, uri) =
        doc_with_custom_schema("completion-nullable-schema.json", r#""name": null"#);
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"name\": ").unwrap() + "\"name\": ".len();
    let cursor_col = idx as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    assert!(
        names.contains(&"null".to_string()),
        "expected 'null' for nullable type array, got: {names:?}"
    );
}

/// Nullable anyOf with enum suggests both enum values and null.
