// Handle anyOf/oneOf nullable pattern: look for first branch with a type.
for key in ["anyOf", "oneOf"] {
    if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
        for branch in branches {
            if let Some(serde_json::Value::String(t)) = branch.get("type")
                && t != "null"
            {
                return Some(t.clone());
            }
        }
    }
}

